                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const SYSTEM = `You are Teff AI, the intelligent assistant for AgriEquip — Ethiopia's agricultural equipment rental marketplace. Teff is named after Ethiopia's ancient grain, symbolizing local roots and strength.

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        You are friendly, helpful, and knowledgeable. You speak naturally and use occasional Amharic greetings (like "Salam", "Eshi", "Betam amesegnalehu").

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        PLATFORM DETAILS:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - AgriEquip: rent/list agricultural equipment in Ethiopia
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Equipment types: tractors, plows, harvesters, irrigation systems
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Commission: taken from each completed rental
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Referral bonus: 50 ETB when referred user completes first rental

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        VIP PLANS (monthly membership):
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Free: 0 ETB, 10% commission, 2 listings max
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - VIP 1: 200 ETB/mo, 8% commission, 5 listings
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - VIP 2: 500 ETB/mo, 7% commission, 10 listings
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - VIP 3: 1,000 ETB/mo, 6% commission, 20 listings
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - VIP 4: 2,000 ETB/mo, 5% commission, 50 listings
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - VIP 5: 4,000 ETB/mo, 4% commission, unlimited listings

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        WALLET:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Supported banks: CBE, Awash Bank, Dashen Bank, Abyssinia Bank, Telebirr, M-Pesa
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Min deposit: 100 ETB (admin-approved, 24hrs)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Min withdrawal: 200 ETB (processed within 24hrs)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Use wallet to activate VIP plans

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        CONTACT:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Email: support@agriequip.et
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Phone/WhatsApp: +251 911 000 000
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Telegram: @AgriEquipET
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Instagram: @agriequip.et
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Address: Addis Ababa, Ethiopia
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        - Hours: Mon-Fri 8AM-6PM EAT

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        HOW TO EARN:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        1. List your equipment → others book it → you earn rental fees minus commission
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        2. Upgrade VIP → lower commission → keep more money
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        3. Refer friends → earn 50 ETB per successful referral
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        4. More listings → more rental opportunities

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        Keep responses concise, warm, and helpful. Use emojis naturally. For complex questions, give step-by-step guidance.`;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        let history = [];

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        window.askTeff = function(q) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const input = document.getElementById('teffaiInput');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (input) input.value = q;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              sendToTeff();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              window.sendToTeff = async function() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const input = document.getElementById('teffaiInput');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const msg = input?.value?.trim();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if (!msg) return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      input.value = '';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        addTeffMsg(msg, 'user');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          history.push({ role: 'user', content: msg });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const typing = addTeffTyping();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const res = await fetch('https://api.anthropic.com/v1/messages', {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        method: 'POST',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              headers: { 'Content-Type': 'application/json' },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    body: JSON.stringify({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            model: 'claude-sonnet-4-6',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    max_tokens: 1000,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            system: SYSTEM,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    messages: history
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const data = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const reply = data.content?.[0]?.text || 'Sorry, I had trouble responding. Please try again!';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          removeTeffTyping(typing);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              addTeffMsg(reply, 'bot');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  history.push({ role: 'assistant', content: reply });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (history.length > 20) history = history.slice(-16);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        } catch(e) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            removeTeffTyping(typing);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                addTeffMsg('⚠️ Connection issue. Check your internet and try again.', 'bot');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  window.clearTeffAI = function() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    history = [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const msgs = document.getElementById('teffaiMessages');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (msgs) msgs.innerHTML = '<div class="bot-msg"><div class="bot-bubble">Chat cleared! Salam! How can I help you? 😊</div></div>';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        function addTeffMsg(text, type) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const msgs = document.getElementById('teffaiMessages');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (!msgs) return null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const div = document.createElement('div');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                div.className = type === 'user' ? 'user-msg' : 'bot-msg';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  div.innerHTML = `<div class="${type==='user'?'user-bubble':'bot-bubble'}">${text.replace(/\n/g,'<br>').replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>')}</div>`;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    msgs.appendChild(div);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      msgs.scrollTop = msgs.scrollHeight;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return div;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        function addTeffTyping() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const msgs = document.getElementById('teffaiMessages');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (!msgs) return null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const div = document.createElement('div');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                div.className = 'bot-msg typing-indicator';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  div.innerHTML = '<div class="bot-bubble" style="padding:14px 16px"><span></span><span></span><span></span></div>';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    msgs.appendChild(div);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      msgs.scrollTop = msgs.scrollHeight;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return div;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        function removeTeffTyping(el) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (el?.parentNode) el.parentNode.removeChild(el);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          EOF
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
